svg.script:
const data = [
  { 
    title: "مساحة إعلانية متاحة", 
    desc: 'تواصل مع إدارة "صوان" لحجز هذه المساحة', 
    align: "end"    // RTL يظهر من اليمين (نقطة النهاية في المركز)
  },
  { 
    title: "Advertising space available", 
    desc: "Contact Siwane management to reserve this space", 
    align: "start"  // LTR يبدأ من المركز لليسار
  }
];

const mainEl = document.getElementById("text-main");
const subEl = document.getElementById("text-sub");

// دالة كتابة النص حرفاً حرفاً مع مؤشر وامض
async function typeText(el, text, speed) {
  el.textContent = "";
  for (let i = 0; i < text.length; i++) {
    el.textContent = text.substring(0, i + 1) + "|";
    await new Promise(r => setTimeout(r, speed));
  }
  // إزالة المؤشر بعد الانتهاء
  el.textContent = text;
}

// دورة لا نهائية تتنقل بين اللغتين
async function startLoop() {
  let i = 0;
  while (true) {
    const item = data[i % 2];

    // ضبط محاذاة النص حسب اللغة (بدون استخدام direction)
    mainEl.setAttribute("text-anchor", item.align);
    subEl.setAttribute("text-anchor", item.align);

    // كتابة العنوان والوصف
    await typeText(mainEl, item.title, 80);
    await typeText(subEl, item.desc, 45);

    // إبقاء النص ظاهراً لمدة 5 ثوانٍ للقراءة
    await new Promise(r => setTimeout(r, 5000));

    // مسح النصوص استعداداً للجملة التالية
    mainEl.textContent = "";
    subEl.textContent = "";

    // فاصل قصير 300 مللي ثانية قبل البدء بالجملة الجديدة
    await new Promise(r => setTimeout(r, 300));
    i++;
  }
}

startLoop();
